import axios from 'axios';
import { useEffect, useState } from 'react';

function App() {
  const [plots, setPlots] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:5001/api/plots')
      .then(res => setPlots(res.data))
      .catch(err => console.error(err));
  }, []);

  const [name, setName] = useState('');
  const [size, setSize] = useState('');
  const [plants, setPlants] = useState('');
  const addPlot = async () => {
    const res = await axios.post('http://localhost:5001/api/plots', {
      name,
      size,
      plants
    });
    setPlots([...plots, res.data]);
  };

  const deletePlot = async (id) => {
    await axios.delete(`http://localhost:5001/api/plots/${id}`);
    setPlots(plots.filter(plot => plot._id !== id));
  };

  const updatePlot = async (id, status) => {
    const res = await axios.put(`http://localhost:5001/api/plots/${id}`, {
      status
    });
    setPlots(plots.map(p => p._id === id ? res.data : p));
  };


  return (
    <div style={{ display: "flex", height: "100vh" }}>

      {/* Sidebar */}
      <div style={{ width: "220px", background: "#1f2937", color: "white", padding: "20px" }}>
        <div style={{height: "50px"}}></div>
        <h2>Garden</h2>
        <p>Dashboard</p>
        <p style={{ fontWeight: "bold" }}>Manage Plot</p>
        <p>Manage Users</p>
        <p>Settings</p>
      </div>

      {/* Main Content */}
      <div style={{ flex: 1, padding: "20px" }}>

        {/* Top Bar */}
        <div style={{ marginBottom: "20px", textAlign: "center"}}>
          <h1><b>Garden Manager Dashboard</b></h1>
        </div>

        {/* Plot Section */}
        <div>
          <div style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "15px",
            padding: "15px",
            border: "1px solid #ddd",
            borderRadius: "8px",
            backgroundColor: "#f9fafb"
          }}>
            <h3 style={{ margin: 0 }}>Plot List</h3>

            <div style={{ display: "flex", alignItems: "center" }}>
              <input
                placeholder="Plot name"
                onChange={(e) => setName(e.target.value)}
                style={{
                  padding: "8px",
                  border: "1px solid #ccc",
                  borderRadius: "5px",
                  outline: "none",
                  marginRight: "10px"
                }}
              />

              <input
                placeholder="Size (e.g. 10x10)"
                onChange={(e) => setSize(e.target.value)}
                style={{
                  padding: "8px",
                  border: "1px solid #ccc",
                  borderRadius: "5px",
                  outline: "none",
                  marginRight: "10px"
                }}
              />

              <input
                placeholder="Plants"
                onChange={(e) => setPlants(e.target.value)}
                style={{
                  padding: "8px",
                  border: "1px solid #ccc",
                  borderRadius: "5px",
                  outline: "none"
                }}
              />

              <button
                onClick={addPlot}
                style={{
                  marginLeft: "10px",
                  padding: "8px 12px",
                  backgroundColor: "#16a34a",
                  color: "white",
                  border: "none",
                  borderRadius: "5px",
                  cursor: "pointer"
                }}
              >
                + Add Plot
              </button>
            </div>
          </div>

          <table style={{ width: "100%", borderCollapse: "collapse" }} border="1">
            <thead>
              <tr>
                <th>Name</th>
                <th>Size</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>

            <tbody style={{textAlign: "center"}}>
              {plots.map(plot => (
                <tr key={plot._id}>
                  <td>{plot.name}</td>
                  <td>{plot.size}</td>
                  <td>
                    <select
                      value={plot.status}
                      onChange={(e) => updatePlot(plot._id, e.target.value)}
                      style={{
                        padding: "5px",
                        borderRadius: "5px",
                        border: "1px solid #ccc"
                      }}
                    >
                      <option value="Available">Available</option>
                      <option value="Occupied">Occupied</option>
                    </select>
                  </td>
                  <td>
                    {/* <button onClick={() => updatePlot(plot._id)}>Update</button> */}
                    <button onClick={() => deletePlot(plot._id)} style={{ marginLeft: "10px" }}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

        </div>

      </div>
    </div>
  );
}

export default App;
